{
  "name": "@splitzy/shared-zero",
  "version": "0.0.0",
  "private": true,
  "type": "module",
  "exports": {
    "./schema": {
      "types": "./dist/schema.d.ts",
      "default": "./dist/schema.js"
    },
    "./mutators": {
      "types": "./dist/mutators.d.ts",
      "default": "./dist/mutators.js"
    },
    "./queries": {
      "types": "./dist/queries.d.ts",
      "default": "./dist/queries.js"
    },
    "./rebalance-shares": {
      "types": "./dist/rebalance-shares.d.ts",
      "default": "./dist/rebalance-shares.js"
    }
  },
  "files": [
    "dist"
  ],
  "scripts": {
    "build": "tsc",
    "dev": "tsc -w",
    "test": "vitest run",
    "type-check": "tsc --noEmit",
    "format": "prettier --check .",
    "format:fix": "prettier --write --ignore-unknown .",
    "check": "pnpm run format && pnpm run type-check"
  },
  "dependencies": {
    "@rocicorp/zero": "^0.25.12",
    "decimal.js": "^10.6.0",
    "zod": "^4.2.1"
  },
  "devDependencies": {
    "@types/node": "^20.11.17",
    "prettier": "^3.8.1",
    "typescript": "^5.8.3",
    "vitest": "^3.2.4"
  }
}

